#include <stdio.h>
#define MAX_N 100
#define MAX_FLAGS 10000

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int ai[N], pi[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &ai[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &pi[i]);
        }
        double dp[N][2 * MAX_FLAGS + 1];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j <= 2 * MAX_FLAGS; j++) {
                dp[i][j] = 0.0;
            }
        }
        dp[0][ai[0]] = (double)pi[0] / 100.0;
        dp[0][0] = (double)(100 - pi[0]) / 100.0;
        for (int i = 1; i < N; i++) {
            for (int j = 0; j <= 2 * MAX_FLAGS; j++) {
                if (j - ai[i] >= 0) {
                    dp[i][j] += dp[i - 1][j - ai[i]] * (double)pi[i] / 100.0;
                }
                if (j + ai[i] <= 2 * MAX_FLAGS) {
                    dp[i][j] += dp[i - 1][j + ai[i]] * (double)(100 - pi[i]) / 100.0;
                }
            }
        }
        double ans = 0.0;
        for (int i = MAX_FLAGS; i <= 2 * MAX_FLAGS; i++) {
            ans += dp[N - 1][i];
        }
        printf("%.6f\n", ans);
    }
    return 0;
}

